import React from 'react';
import EmployeeCard from './EmployeeCard';

/**
 * EmployeeList component for displaying a list of employees
 * @param {Object} props - Component props
 * @param {Array} props.employees - Array of employee objects
 * @param {Function} props.onEdit - Callback function for editing an employee
 * @param {Function} props.onDelete - Callback function for deleting an employee
 */
const EmployeeList = ({ employees, onEdit, onDelete }) => {
  /**
   * Render empty state when no employees are found
   */
  const renderEmptyState = () => (
    <div className="empty-state">
      <h3>No Employees Found</h3>
      <p>No employees match your current search criteria.</p>
      <p>Try adjusting your search or add new employees to get started.</p>
    </div>
  );

  /**
   * Render the list of employees
   */
  const renderEmployeeList = () => (
    <div className="employee-list">
      <div className="employee-list-header">
        <h2>Employees ({employees.length})</h2>
      </div>
      <div className="employee-grid">
        {employees.map((employee) => (
          <EmployeeCard
            key={employee._id}
            employee={employee}
            onEdit={onEdit}
            onDelete={onDelete}
          />
        ))}
      </div>
    </div>
  );

  return (
    <div className="employee-list-container">
      {employees.length === 0 ? renderEmptyState() : renderEmployeeList()}
    </div>
  );
};

export default EmployeeList;
